import{_ as t}from"./chunks/subs-grants-king.Bdji-M7h.js";import{_ as e,o,c as i,a0 as n}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Share Kingdom Quotas with Allocations","description":"","frontmatter":{},"headers":[],"relativePath":"subscriptions/allocations.md","filePath":"subscriptions/allocations.md"}'),l={name:"subscriptions/allocations.md"};function s(r,a,h,c,g,d){return o(),i("div",null,[...a[0]||(a[0]=[n('<h1 id="share-kingdom-quotas-with-allocations" tabindex="-1">Share Kingdom Quotas with Allocations <a class="header-anchor" href="#share-kingdom-quotas-with-allocations" aria-label="Permalink to &quot;Share Kingdom Quotas with Allocations&quot;">​</a></h1><p>When a King <a href="./kingdom-grants.html">grants</a> the kingdom&#39;s premium plan to several alliances, they all draw on the <strong>same</strong> kingdom limits. <strong>Allocations</strong> let a King divide those limits up — giving each granted alliance its own slice — so one alliance can&#39;t use up everything. This guide is for <strong>Kings</strong> (and Supreme Admins).</p><h2 id="what-an-allocation-is" tabindex="-1">What an allocation is <a class="header-anchor" href="#what-an-allocation-is" aria-label="Permalink to &quot;What an allocation is&quot;">​</a></h2><p>An <strong><a href="./../getting-started/glossary.html#allocation">allocation</a></strong> is a per-alliance cap on a specific resource, carved out of the kingdom&#39;s plan limit. For example, if your kingdom plan allows 5,000 players in total, you might allocate 1,000 to one granted alliance and 800 to another.</p><p>You set allocations from the same <strong>kingdom detail page</strong> where you manage grants.</p><p><img src="'+t+'" alt="Grant and allocation table on the kingdom page"></p><h2 id="the-rules" tabindex="-1">The rules <a class="header-anchor" href="#the-rules" aria-label="Permalink to &quot;The rules&quot;">​</a></h2><ul><li>You can only allocate to an alliance that has a grant (offered or accepted). Allocating to an alliance you haven&#39;t granted to is refused.</li><li><strong>Allocations only take effect once the grant is accepted.</strong> Setting them up on a pending offer is fine, but they do nothing until the alliance accepts.</li><li>For each resource, the <strong>total you allocate across alliances can&#39;t exceed the kingdom&#39;s own limit</strong>. If you try, the app blocks it with an &quot;allocation exceeds kingdom quota&quot; message.</li></ul><h2 id="setting-allocations" tabindex="-1">Setting allocations <a class="header-anchor" href="#setting-allocations" aria-label="Permalink to &quot;Setting allocations&quot;">​</a></h2><ol><li>Open your kingdom detail page.</li><li>In the allocation table, find the granted alliance.</li><li>Set the per-resource amounts you want to reserve for that alliance.</li><li>Save.</li></ol><p>The table shows your totals against the kingdom limit so you can see how much is still unallocated.</p><h2 id="how-allocations-interact-with-a-granted-alliance-s-limits" tabindex="-1">How allocations interact with a granted alliance&#39;s limits <a class="header-anchor" href="#how-allocations-interact-with-a-granted-alliance-s-limits" aria-label="Permalink to &quot;How allocations interact with a granted alliance&#39;s limits&quot;">​</a></h2><p>For an alliance running on a granted kingdom plan, the app decides its limit for each resource in this order:</p><ol><li>A <strong>special override</strong> for that alliance (if a Supreme Admin set one).</li><li>The <strong>allocation</strong> you gave it (if any).</li><li>Otherwise, the <strong>plan&#39;s</strong> own limit.</li></ol><p>So an allocation is the King&#39;s way of saying &quot;this granted alliance gets <em>this much</em> of the kingdom plan,&quot; without changing the plan itself.</p><h2 id="if-you-revoke-the-grant" tabindex="-1">If you revoke the grant <a class="header-anchor" href="#if-you-revoke-the-grant" aria-label="Permalink to &quot;If you revoke the grant&quot;">​</a></h2><p>Revoking a grant removes that alliance&#39;s allocations along with it. If you re-grant later, you&#39;ll set allocations again.</p><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="./kingdom-grants.html">Kingdom Grants</a> — offering premium to alliances in the first place.</li><li><a href="./quota-warnings.html">Quota Warnings</a> — what a granted alliance sees as it approaches its allocated limits.</li></ul>',19)])])}const f=e(l,[["render",s]]);export{p as __pageData,f as default};
